54	// GraphIssue is a structured description of a problem in the document graph.
55	// Kind groups issues for UI rollups; Path and ID locate the offending document
56	// (both may be empty when the issue is not tied to a single file, e.g. a
57	// cycle). RelatedPath points at a second file when the issue describes a
58	// relationship, e.g. the pre-existing document a duplicate ID collides with.
59	type GraphIssue struct {
60		Kind        IssueKind `json:"kind"`
61		Path        string    `json:"path,omitempty"`
