192			doc, err := ParseDocument(filePath)
193			if err != nil {
194				if errors.Is(err, ErrNotDocGraphDocument) {
195					continue
196				}
197				if errors.Is(err, ErrPromptMetadataOversize) {
198					return nil, err
199				}
200				issues = append(issues, GraphIssue{
201					Kind:    IssueParseError,
202					Path:    relPath(cleanRoot, filePath),
203					Message: fmt.Sprintf("%s: %v", filePath, err),
204				})
205				continue
206			}
207			if existing, exists := documents[doc.ID]; exists {
208				issues = append(issues, GraphIssue{
209					Kind:        IssueDuplicateID,
210					Path:        relPath(cleanRoot, filePath),
211					ID:          doc.ID,
212					Message:     fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath),
213					RelatedPath: existing.Path,
214				})
215				continue
216			}
217			doc.Path = relPath(cleanRoot, filePath)
218			documents[doc.ID] = doc
219			pathToID[doc.Path] = doc.ID
220		}
221	
222		g := &Graph{
223			RootDir:   cleanRoot,
224			Documents: documents,
225			PathToID:  pathToID,
226			Issues:    issues,
227		}
228		g.resolveBodyLinks()
229		g.buildDependents()
230		g.detectMissingDeps()
231		g.detectCycles()
232		g.applyConfigDefaults()
233		g.finalizeWarnings()
234		return g, nil
235	}
236	
237	// detectMissingDeps emits missing_dep issues for every declared dependency
238	// that does not resolve to a document in the graph. Runs after body-link
239	// resolution so link targets are already promoted to DependsOn.
240	func (g *Graph) detectMissingDeps() {
241		for _, id := range sortedDocIDs(g.Documents) {
242			doc := g.Documents[id]
243			if doc == nil {
244				continue
245			}
246			for _, dep := range doc.DependsOn {
247				if _, ok := g.Documents[dep]; ok {
248					continue
249				}
250				g.Issues = append(g.Issues, GraphIssue{
251					Kind:    IssueMissingDep,
252					Path:    doc.Path,
253					ID:      dep,
254					Message: fmt.Sprintf("document %q declares dependency %q which is not in the graph", doc.ID, dep),
255				})
256			}
257		}
258	}
259	
260	// sortedDocIDs returns the IDs of docs sorted for stable issue ordering.
261	func sortedDocIDs(docs map[string]*Document) []string {
262		ids := make([]string, 0, len(docs))
263		for id := range docs {
264			ids = append(ids, id)
265		}
266		sort.Strings(ids)
267		return ids
268	}
269	
270	// finalizeWarnings rebuilds the deprecated Warnings string slice from Issues
271	// and sorts Issues deterministically so downstream callers see stable output.
272	func (g *Graph) finalizeWarnings() {
273		sort.SliceStable(g.Issues, func(i, j int) bool {
274			if g.Issues[i].Kind != g.Issues[j].Kind {
275				return g.Issues[i].Kind < g.Issues[j].Kind
276			}
277			return g.Issues[i].Message < g.Issues[j].Message
278		})
279		g.Warnings = MessageLines(g.Issues)
280		if g.Warnings == nil {
281			g.Warnings = []string{}
282		}
283	}
