285	func (g *Graph) applyConfigDefaults() {
286		for _, doc := range g.Documents {
287			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
288			doc.Inputs = dedupeSortedStrings(doc.Inputs)
289		}
290	}
