439	func findMarkdownFiles(root string, roots []string) ([]string, error) {
440		targetDirs := []string{root}
441		if len(roots) > 0 {
442			targetDirs = roots
443		}
444	
445		files := []string{}
446		for _, base := range targetDirs {
447			cleanRoot := filepath.Clean(base)
448			err := filepath.Walk(cleanRoot, func(path string, info os.FileInfo, err error) error {
449				if err != nil {
450					return nil
451				}
452				if info == nil {
453					return nil
454				}
455				if info.IsDir() {
456					name := filepath.Base(path)
457					// Skip tool-managed directories. .claude is the Claude Code
458					// workspace (including throwaway copies under .claude/worktrees/);
459					// a worktrees/ directory at any depth is agent-scratch and must
460					// not be surfaced as canonical documents.
461					switch name {
462					case ".git", ".ddx", ".claude", "worktrees":
463						return filepath.SkipDir
464					}
465					return nil
466				}
467				if strings.HasPrefix(filepath.Base(path), ".") {
468					return nil
469				}
470				ext := strings.ToLower(filepath.Ext(path))
471				if ext != ".md" {
472					return nil
473				}
474				files = append(files, path)
475				return nil
476			})
477			if err != nil {
478				return nil, err
479			}
480		}
481		sort.Strings(files)
482		return files, nil
483	}
484	
485	// relPath returns filePath expressed relative to root. If filePath cannot be
486	// made relative (e.g. different volumes on Windows) the cleaned absolute path
487	// is returned. Callers treat the result as the canonical document path.
488	func relPath(root, filePath string) string {
489		clean := filepath.Clean(filePath)
490		if rel, err := filepath.Rel(root, clean); err == nil && !strings.HasPrefix(rel, ".."+string(filepath.Separator)) && rel != ".." {
491			return rel
492		}
493		return clean
494	}
495	
496	// absPath returns an absolute path for a document path stored on a Graph.
497	// Document paths are relative to g.RootDir; callers that need to touch the
498	// file on disk (read/write/git) must join with the root first.
499	func (g *Graph) absPath(docPath string) string {
500		if filepath.IsAbs(docPath) {
501			return docPath
502		}
503		return filepath.Join(g.RootDir, docPath)
504	}
505	
506	func ParseDocument(path string) (*Document, error) {
507		content, err := os.ReadFile(path)
508		if err != nil {
509			return nil, err
510		}
511	
512		frontmatter, body, err := ParseFrontmatter(content)
513		if err != nil {
514			return nil, err
515		}
516		if !frontmatter.HasFrontmatter || frontmatter.Doc.ID == "" {
517			return nil, fmt.Errorf("%w in %s", ErrNotDocGraphDocument, path)
518		}
519		if observed := len([]byte(frontmatter.Doc.Prompt)); observed > docgraphPromptCapBytes {
520			return nil, fmt.Errorf(
521				"%w: document %q at %s prompt metadata is %d bytes, cap %d bytes (configurable via .ddx/config.yaml:evidence_caps.max_prompt_bytes)",
522				ErrPromptMetadataOversize, frontmatter.Doc.ID, path, observed, docgraphPromptCapBytes)
523		}
524	
525		review := ReviewMetadata{
526			SelfHash:   frontmatter.Doc.Review.SelfHash,
527			ReviewedAt: frontmatter.Doc.Review.ReviewedAt,
528			Deps:       frontmatter.Doc.Review.Deps,
529		}
530		if review.Deps == nil {
531			review.Deps = map[string]string{}
532		}
533	
534		doc := &Document{
535			ID:            frontmatter.Doc.ID,
536			Title:         extractTitle([]byte(body)),
537			DependsOn:     dedupeSortedStrings(frontmatter.Doc.DependsOn),
538			Inputs:        dedupeSortedStrings(frontmatter.Doc.Inputs),
539			Review:        review,
540			ParkingLot:    frontmatter.Doc.ParkingLot,
541			Prompt:        frontmatter.Doc.Prompt,
542			ExecDef:       frontmatter.Doc.Exec,
543			body:          body,
544			bodyLinkTexts: extractBodyLinks(body),
545		}
546		if frontmatter.Raw != nil {
547			doc.frontmatter = frontmatter.Raw
548		}
549	
550		contentHash, err := HashDocument(frontmatter.Raw, body)
551		if err != nil {
552			return nil, err
553		}
554		doc.contentHash = contentHash
555		return doc, nil
556	}
