558	func (g *Graph) buildDependents() {
559		g.Dependents = make(map[string][]string)
560		for id := range g.Documents {
561			g.Dependents[id] = g.Dependents[id][:0]
562		}
563		for id, doc := range g.Documents {
564			for _, dep := range doc.DependsOn {
565				if _, ok := g.Documents[dep]; !ok {
566					continue
567				}
568				if containsString(g.Dependents[dep], id) {
569					continue
570				}
571				g.Dependents[dep] = append(g.Dependents[dep], id)
572			}
573		}
574		for id := range g.Dependents {
575			g.Dependents[id] = dedupeSortedStrings(g.Dependents[id])
576		}
577		for id, doc := range g.Documents {
578			doc.Dependents = append([]string{}, g.Dependents[id]...)
579		}
580	}
581	
582	func (g *Graph) detectCycles() {
583		index := 0
584		indexes := map[string]int{}
585		lowlinks := map[string]int{}
586		onStack := map[string]bool{}
587		stack := []string{}
588		warned := map[string]struct{}{}
589		var visit func(string)
590	
591		visit = func(id string) {
592			indexes[id] = index
593			lowlinks[id] = index
594			index++
595			stack = append(stack, id)
596			onStack[id] = true
597	
598			node := g.Documents[id]
599			for _, dep := range node.DependsOn {
600				if _, ok := g.Documents[dep]; !ok {
601					continue
602				}
603				if _, ok := indexes[dep]; !ok {
604					visit(dep)
605					if lowlinks[dep] < lowlinks[id] {
606						lowlinks[id] = lowlinks[dep]
607					}
608				} else if onStack[dep] {
609					if indexes[dep] < lowlinks[id] {
610						lowlinks[id] = indexes[dep]
611					}
612				}
613			}
614	
615			if lowlinks[id] == indexes[id] {
616				cycle := []string{}
617				for {
618					last := stack[len(stack)-1]
619					stack = stack[:len(stack)-1]
620					onStack[last] = false
621					cycle = append(cycle, last)
622					if last == id {
623						break
624					}
625				}
626				if len(cycle) > 1 {
627					warnKey := cycleKey(cycle)
628					if _, done := warned[warnKey]; done {
629						return
630					}
631					warned[warnKey] = struct{}{}
632					label := renderCycle(cycle)
633					g.Issues = append(g.Issues, GraphIssue{
634						Kind:    IssueCycle,
635						Message: fmt.Sprintf("cycle detected: %s", label),
636					})
637				} else {
638					parent := g.Documents[id]
639					selfDepends := containsString(parent.DependsOn, id)
640					if selfDepends {
641						label := fmt.Sprintf("%s -> %s", id, id)
642						g.Issues = append(g.Issues, GraphIssue{
643							Kind:    IssueCycle,
644							ID:      id,
645							Message: fmt.Sprintf("cycle detected: %s", label),
646						})
647					}
648				}
649			}
650		}
651	
652		for _, id := range sortedDocIDs(g.Documents) {
653			if _, ok := indexes[id]; !ok {
654				visit(id)
655			}
656		}
657	}
658	
659	func cycleKey(ids []string) string {
660		if len(ids) == 0 {
661			return ""
662		}
663		copyIDs := append([]string(nil), ids...)
664		sort.Strings(copyIDs)
665		return strings.Join(copyIDs, "::")
666	}
667	
668	func renderCycle(ids []string) string {
669		if len(ids) == 0 {
670			return ""
671		}
672		copyIDs := append([]string(nil), ids...)
673		sort.Strings(copyIDs)
674		start := copyIDs[0]
675		return start + " -> " + strings.Join(copyIDs[1:], " -> ") + " -> " + start
676	}
677	
678	func (g *Graph) StaleDocs() []StaleReason {
679		if len(g.Documents) == 0 {
680			return nil
681		}
682	
683		direct := map[string][]string{}
684		for id := range g.Documents {
685			doc, ok := g.Documents[id]
686			if !ok || doc.ParkingLot {
687				continue
688			}
689			reasons := staleReasonsForDocument(g, doc)
690			if len(reasons) > 0 {
691				direct[id] = reasons
692			}
693		}
694	
695		final := map[string][]string{}
696		queue := []string{}
697		for id, reasons := range direct {
698			final[id] = append([]string(nil), reasons...)
699			queue = append(queue, id)
700		}
701	
702		seen := map[string]struct{}{}
703		for _, id := range queue {
704			seen[id] = struct{}{}
705		}
706		for i := 0; i < len(queue); i++ {
707			u := queue[i]
708			for _, dep := range g.Dependents[u] {
709				child, ok := g.Documents[dep]
710				if !ok || child.ParkingLot {
711					continue
712				}
713				if _, done := seen[dep]; done {
714					continue
715				}
716				seen[dep] = struct{}{}
717				final[dep] = []string{"upstream stale dependency"}
718				queue = append(queue, dep)
719			}
720		}
721	
722		ids := make([]string, 0, len(final))
723		for id := range final {
724			ids = append(ids, id)
725		}
726		sort.Strings(ids)
727		result := make([]StaleReason, 0, len(ids))
728		for _, id := range ids {
729			doc := g.Documents[id]
730			reason := StaleReason{ID: id, Path: doc.Path, Reasons: final[id]}
731			sort.Strings(reason.Reasons)
732			result = append(result, reason)
733		}
734		return result
735	}
736	
737	func staleReasonsForDocument(g *Graph, doc *Document) []string {
738		reasons := []string{}
739		for _, depID := range doc.DependsOn {
740			depDoc, ok := g.Documents[depID]
741			if !ok {
742				reasons = append(reasons, fmt.Sprintf("missing dependency: %s", depID))
743				continue
744			}
745			expected := doc.Review.Deps[depID]
746			if expected == "" {
747				reasons = append(reasons, fmt.Sprintf("missing review hash for dependency: %s", depID))
748				continue
749			}
750			if expected != depDoc.contentHash {
751				reasons = append(reasons, fmt.Sprintf("dependency changed: %s", depID))
752			}
753		}
754		return dedupeSortedStrings(reasons)
755	}
756	
757	func (g *Graph) StaleReasonForID(id string) (StaleReason, bool) {
758		stale := g.StaleDocs()
759		for _, entry := range stale {
760			if entry.ID == id {
761				return entry, true
762			}
763		}
764		doc, ok := g.Documents[id]
765		if !ok {
766			return StaleReason{}, false
767		}
768		return StaleReason{ID: id, Path: doc.Path, Reasons: nil}, true
769	}
