771	func (g *Graph) Dependencies(id string) ([]string, error) {
772		doc, ok := g.Documents[id]
773		if !ok {
774			return nil, fmt.Errorf("document %q not found", id)
775		}
776		deps := append([]string(nil), doc.DependsOn...)
777		sort.Strings(deps)
778		return deps, nil
779	}
