781	func (g *Graph) DependentIDs(id string) ([]string, error) {
782		doc, ok := g.Documents[id]
783		if !ok {
784			return nil, fmt.Errorf("document %q not found", id)
785		}
786		reqs := append([]string(nil), doc.Dependents...)
787		sort.Strings(reqs)
788		return reqs, nil
