791	func (g *Graph) ResolvePathsToIDs(targets []string) ([]string, error) {
792		ids := make([]string, 0, len(targets))
793		seen := map[string]struct{}{}
794		for _, target := range targets {
795			if target == "" {
796				continue
797			}
798			if id, ok := g.Documents[target]; ok {
799				if _, done := seen[id.ID]; !done {
800					seen[id.ID] = struct{}{}
801					ids = append(ids, id.ID)
802				}
803				continue
804			}
805			resolved := target
806			if !filepath.IsAbs(resolved) {
807				resolved = filepath.Join(g.RootDir, resolved)
808			}
809			resolved = filepath.Clean(resolved)
810			lookupKey := relPath(g.RootDir, resolved)
811			if id, ok := g.PathToID[lookupKey]; ok {
812				if _, done := seen[id]; !done {
813					seen[id] = struct{}{}
814					ids = append(ids, id)
815				}
816				continue
817			}
818			if info, err := os.Stat(resolved); err == nil && info.IsDir() {
819				err := filepath.Walk(resolved, func(path string, info os.FileInfo, err error) error {
820					if err != nil {
821						return nil
822					}
823					if info.IsDir() {
824						switch info.Name() {
825						case ".git", ".ddx", ".claude", "worktrees":
826							return filepath.SkipDir
827						}
828						return nil
829					}
830					if strings.EqualFold(filepath.Ext(path), ".md") {
831						walkKey := relPath(g.RootDir, path)
832						if id, ok := g.PathToID[walkKey]; ok {
833							if _, done := seen[id]; !done {
834								seen[id] = struct{}{}
835								ids = append(ids, id)
836							}
837						}
838					}
839					return nil
840				})
841				if err != nil {
842					return nil, err
843				}
844				continue
845			}
846			return nil, fmt.Errorf("cannot resolve target %q", target)
847		}
848		if len(ids) == 0 {
849			return nil, fmt.Errorf("no matching targets")
850		}
851		return dedupeSortedStrings(ids), nil
852	}
853	
854	func (g *Graph) Stamp(targets []string, now time.Time) ([]string, []string, error) {
855		docIDs, err := g.ResolvePathsToIDs(targets)
856		if err != nil {
857			return nil, nil, err
858		}
859	
860		stamped := make([]string, 0, len(docIDs))
861		warnings := []string{}
862		for _, id := range docIDs {
863			doc, ok := g.Documents[id]
864			if !ok {
865				warnings = append(warnings, fmt.Sprintf("document %q not found", id))
866				continue
867			}
868			if doc.frontmatter == nil {
869				warnings = append(warnings, fmt.Sprintf("document %q missing frontmatter", id))
870				continue
871			}
872			review := ReviewMetadata{
873				SelfHash:   doc.contentHash,
874				ReviewedAt: now.UTC().Format(time.RFC3339),
875				Deps:       map[string]string{},
876			}
877			for _, depID := range doc.DependsOn {
878				if dep, ok := g.Documents[depID]; ok {
879					review.Deps[depID] = dep.contentHash
880				}
881			}
882			if review.Deps == nil {
883				review.Deps = map[string]string{}
884			}
885			reviewForWrite := DocReview(review)
886			err := SetReview(doc.frontmatter, reviewForWrite)
887			if err != nil {
888				return stamped, warnings, err
889			}
890			frontmatterText, err := EncodeFrontmatter(doc.frontmatter)
891			if err != nil {
892				return stamped, warnings, err
893			}
894			updated := frontmatterSeparator + "\n" + frontmatterText + "\n" + frontmatterSeparator + "\n" + doc.body
895			if err := os.WriteFile(g.absPath(doc.Path), []byte(updated), 0644); err != nil {
896				return stamped, warnings, err
897			}
898			if doc.Review.ReviewedAt == "" || doc.Review.SelfHash != review.SelfHash {
899				doc.Review = review
900			}
901			stamped = append(stamped, id)
902		}
903		sort.Strings(stamped)
904		return stamped, warnings, nil
905	}
