974	var bodyLinkPattern = regexp.MustCompile(`\[\[([^\[\]]+)\]\]`)
975	
976	// extractBodyLinks returns the raw text inside every [[...]] span in body.
977	// Nested or malformed brackets are skipped.
978	func extractBodyLinks(body string) []string {
979		matches := bodyLinkPattern.FindAllStringSubmatch(body, -1)
980		if len(matches) == 0 {
981			return nil
982		}
983		out := make([]string, 0, len(matches))
984		for _, m := range matches {
985			text := strings.TrimSpace(m[1])
986			if text != "" {
987				out = append(out, text)
988			}
989		}
990		return out
991	}
