993	// slugifyID converts a wikilink label into a lowercase-hyphen slug suitable
994	// for ID matching. Dots are preserved (dotted IDs). Spaces and underscores
995	// become hyphens. Other non-alphanumeric characters are dropped.
996	func slugifyID(text string) string {
997		var b strings.Builder
998		prevHyphen := false
999		for _, r := range strings.ToLower(text) {
1000			switch {
1001			case unicode.IsLetter(r) || unicode.IsDigit(r) || r == '.':
1002				b.WriteRune(r)
1003				prevHyphen = false
1004			case r == '-' || r == '_' || unicode.IsSpace(r):
1005				if !prevHyphen && b.Len() > 0 {
1006					b.WriteByte('-')
1007					prevHyphen = true
1008				}
1009			}
1010		}
1011		result := b.String()
1012		return strings.TrimRight(result, "-")
1013	}
1014	
1015	// resolveBodyLinks merges body [[ID]] references into each document's DependsOn.
1016	func (g *Graph) resolveBodyLinks() {
1017		for _, doc := range g.Documents {
1018			if len(doc.bodyLinkTexts) == 0 {
1019				continue
1020			}
1021			for _, text := range doc.bodyLinkTexts {
1022				resolved := resolveBodyLinkText(text, g.Documents)
1023				if resolved == "" || resolved == doc.ID {
1024					continue
1025				}
1026				if !containsString(doc.DependsOn, resolved) {
1027					doc.DependsOn = append(doc.DependsOn, resolved)
1028				}
1029			}
1030			doc.DependsOn = dedupeSortedStrings(doc.DependsOn)
1031		}
1032	}
1033	
1034	// resolveBodyLinkText tries to resolve a raw wikilink text to a document ID.
1035	// Resolution order: exact match, then slug match.
1036	func resolveBodyLinkText(text string, docs map[string]*Document) string {
1037		if _, ok := docs[text]; ok {
1038			return text
1039		}
1040		slug := slugifyID(text)
1041		if slug != text {
1042			if _, ok := docs[slug]; ok {
1043				return slug
1044			}
1045		}
1046		return ""
1047	}
1048	
1049	func LoadGraphConfigs(workingDir string) ([]GraphConfig, error) {
1050		cfgDir := filepath.Join(workingDir, ".ddx", "graphs")
1051		entries, err := os.ReadDir(cfgDir)
1052		if err != nil {
1053			if os.IsNotExist(err) {
1054				return nil, nil
1055			}
1056			return nil, err
1057		}
1058	
1059		configs := []GraphConfig{}
1060		for _, entry := range entries {
1061			if entry.IsDir() {
1062				continue
1063			}
1064			ext := strings.ToLower(filepath.Ext(entry.Name()))
1065			if ext != ".yml" && ext != ".yaml" {
1066				continue
1067			}
1068			cfgPath := filepath.Join(cfgDir, entry.Name())
1069			raw, err := os.ReadFile(cfgPath)
1070			if err != nil {
1071				return nil, fmt.Errorf("read graph config %q: %w", cfgPath, err)
1072			}
1073			var cfg GraphConfig
1074			if err := yaml.Unmarshal(raw, &cfg); err != nil {
1075				return nil, fmt.Errorf("parse graph config %q: %w", cfgPath, err)
1076			}
1077			configs = append(configs, cfg)
1078		}
1079		sort.Slice(configs, func(i, j int) bool {
1080			return len(configs[i].Roots) > len(configs[j].Roots)
1081		})
1082		return configs, nil
1083	}
