12	// DocFrontmatter holds the parsed ddx: (or legacy dun:) frontmatter block.
13	type DocFrontmatter struct {
14		ID         string      `yaml:"id"`
15		DependsOn  []string    `yaml:"depends_on"`
16		Prompt     string      `yaml:"prompt"`
17		Inputs     []string    `yaml:"inputs"`
18		Review     DocReview   `yaml:"review"`
19		ParkingLot bool        `yaml:"parking_lot"`
20		Exec       *DocExecDef `yaml:"execution"`
21	}
22	
23	// DocExecDef describes an execution definition embedded in a graph document.
24	// The YAML key is "execution" (matching the ddx: frontmatter convention).
25	// Fields are flat to match the authored document format:
26	//
27	//	ddx:
28	//	  execution:
29	//	    kind: command
30	//	    required: true
31	//	    command: ["make", "test"]
32	//	    cwd: cli
33	//	    timeout_ms: 120000
34	//	    comparison: lower-is-better
35	//	    thresholds:
36	//	      ratchet: 250
37	//	      unit: ms
38	//	    metric:
39	//	      metric_id: MET-API-LATENCY
40	//
41	// ArtifactIDs is optional; when absent, the document's depends_on list is used
42	// to determine which artifacts this execution is linked to. Comparison,
43	// Thresholds, and Metric declare the ratchet evaluation applied by the
44	// landing gate when the command exits 0: the gate parses a numeric observed
45	// value out of stdout and compares it against the ratchet threshold before
46	// allowing the attempt to merge.
47	type DocExecDef struct {
48		Kind        string            `yaml:"kind"`
49		Command     []string          `yaml:"command"`
50		Cwd         string            `yaml:"cwd"`
51		Env         map[string]string `yaml:"env"`
52		TimeoutMS   int               `yaml:"timeout_ms"`
53		ArtifactIDs []string          `yaml:"artifact_ids"`
54		Required    bool              `yaml:"required"`
55		Active      bool              `yaml:"active"`
56		Comparison  string            `yaml:"comparison"`
57		Thresholds  *DocThresholds    `yaml:"thresholds"`
58		Metric      *DocMetricSpec    `yaml:"metric"`
59	}
60	
61	// DocThresholds captures the ratchet policy declared alongside an execution
62	// definition. Ratchet is the value the landing gate enforces; unit is only
63	// used for evidence reporting.
64	type DocThresholds struct {
65		Ratchet float64 `yaml:"ratchet"`
66		Warn    float64 `yaml:"warn"`
67		Unit    string  `yaml:"unit"`
68	}
69	
70	// DocMetricSpec names the metric artifact a gate observes. Optional — a gate
71	// without a metric can still declare thresholds, in which case the definition
72	// ID is used as the metric identifier on ratchet evidence.
73	type DocMetricSpec struct {
74		MetricID string `yaml:"metric_id"`
75		Unit     string `yaml:"unit"`
76	}
77	
78	// DocReview holds staleness tracking metadata.
79	type DocReview struct {
80		SelfHash   string            `yaml:"self_hash"`
81		Deps       map[string]string `yaml:"deps"`
82		ReviewedAt string            `yaml:"reviewed_at"`
83	}
84	
85	// Frontmatter is the parsed result from a markdown file.
86	type Frontmatter struct {
87		Doc            DocFrontmatter
88		Raw            *yaml.Node
89		HasFrontmatter bool
90		// Namespace records which prefix was found: "ddx" or "dun".
91		Namespace string
92	}
93	
94	// ParseFrontmatter parses YAML frontmatter from markdown content.
95	// It reads both ddx: and dun: namespaces (preferring ddx: if both present).
96	// Returns the parsed frontmatter, the body text after the closing ---, and any error.
97	func ParseFrontmatter(content []byte) (Frontmatter, string, error) {
98		frontmatterText, body, ok := splitFrontmatter(content)
99		if !ok {
100			return Frontmatter{}, string(content), nil
101		}
102	
103		trimmed := strings.TrimSpace(frontmatterText)
104	
105		// Try ddx: first, then dun: for backward compatibility
106		var doc DocFrontmatter
107		namespace := ""
108	
109		var ddxWrapper struct {
110			DDx DocFrontmatter `yaml:"ddx"`
111		}
112		if err := yaml.Unmarshal([]byte(trimmed), &ddxWrapper); err != nil {
113			return Frontmatter{}, "", fmt.Errorf("parse frontmatter: %w", err)
114		}
115		if ddxWrapper.DDx.ID != "" {
116			doc = ddxWrapper.DDx
117			namespace = "ddx"
118		} else {
119			var dunWrapper struct {
120				Dun DocFrontmatter `yaml:"dun"`
121			}
122			if err := yaml.Unmarshal([]byte(trimmed), &dunWrapper); err != nil {
123				return Frontmatter{}, "", fmt.Errorf("parse frontmatter: %w", err)
124			}
125			if dunWrapper.Dun.ID != "" {
126				doc = dunWrapper.Dun
127				namespace = "dun"
128			}
129		}
130	
131		var node yaml.Node
132		if err := yaml.Unmarshal([]byte(trimmed), &node); err != nil {
133			return Frontmatter{}, "", fmt.Errorf("parse frontmatter node: %w", err)
134		}
135	
136		var root *yaml.Node
137		if len(node.Content) > 0 {
138			root = node.Content[0]
139		}
140	
141		return Frontmatter{
142			Doc:            doc,
143			Raw:            root,
144			HasFrontmatter: true,
145			Namespace:      namespace,
146		}, body, nil
147	}
148	
149	// MigrateLegacyDunFrontmatter converts top-level `dun:` metadata to `ddx:`.
150	//
151	// Migration is lossless for fields:
152	//   - If both `ddx` and `dun` are present, keys from `dun` are merged into `ddx`
153	//     when missing.
154	//   - If only `dun` is present, it is renamed to `ddx`.
155	//   - If `ddx` is already present and no other legacy-compatible namespace exists,
156	//     no changes are made.
157	func MigrateLegacyDunFrontmatter(root *yaml.Node) bool {
158		if root == nil || root.Kind != yaml.MappingNode {
159			return false
160		}
161	
162		ddxNode := findMappingValue(root, "ddx")
163		dunNode := findMappingValue(root, "dun")
164		if dunNode == nil {
165			return false
166		}
167	
168		if ddxNode == nil {
169			dunKey := findMappingKey(root, "dun")
170			if dunKey != nil {
171				dunKey.Value = "ddx"
172			}
173			return true
174		}
175	
176		// Merge legacy keys into ddx only when missing.
177		mergeIntoDDX(ddxNode, dunNode)
178	
179		removeMappingKey(root, "dun")
180		return true
181	}
