183	func splitFrontmatter(content []byte) (string, string, bool) {
184		if !bytes.HasPrefix(content, []byte("---")) {
185			return "", string(content), false
186		}
187	
188		firstLineEnd := bytes.IndexByte(content, '\n')
189		if firstLineEnd == -1 {
190			return "", string(content), false
191		}
192	
193		firstLine := bytes.TrimRight(content[:firstLineEnd], "\r")
194		if !bytes.Equal(firstLine, []byte("---")) {
195			return "", string(content), false
196		}
197	
198		rest := content[firstLineEnd+1:]
199		idx := 0
200		for idx <= len(rest) {
201			lineEnd := bytes.IndexByte(rest[idx:], '\n')
202			if lineEnd == -1 {
203				lineEnd = len(rest) - idx
204			}
205			line := rest[idx : idx+lineEnd]
206			lineTrimmed := bytes.TrimRight(line, "\r")
207			if bytes.Equal(lineTrimmed, []byte("---")) {
208				frontmatter := rest[:idx]
209				bodyStart := idx + lineEnd
210				if idx+lineEnd < len(rest) && rest[idx+lineEnd] == '\n' {
211					bodyStart = idx + lineEnd + 1
212				}
213				return string(frontmatter), string(rest[bodyStart:]), true
214			}
215			if idx+lineEnd >= len(rest) {
216				break
217			}
218			idx += lineEnd + 1
219		}
220	
221		return "", string(content), false
222	}
