259	// EncodeFrontmatter encodes a YAML node back to string.
260	func EncodeFrontmatter(root *yaml.Node) (string, error) {
261		if root == nil {
262			return "", fmt.Errorf("frontmatter missing")
263		}
264		var buf strings.Builder
265		enc := yaml.NewEncoder(&buf)
266		enc.SetIndent(2)
267		if err := enc.Encode(root); err != nil {
268			return "", err
269		}
270		if err := enc.Close(); err != nil {
271			return "", err
272		}
273		return strings.TrimRight(buf.String(), "\n"), nil
274	}
