276	func ensureMappingNode(parent *yaml.Node, key string) *yaml.Node {
277		if parent.Kind != yaml.MappingNode {
278			parent.Kind = yaml.MappingNode
279		}
280		for i := 0; i < len(parent.Content); i += 2 {
281			k := parent.Content[i]
282			if k.Value == key {
283				v := parent.Content[i+1]
284				if v.Kind != yaml.MappingNode {
285					v.Kind = yaml.MappingNode
286					v.Content = nil
287				}
288				return v
289			}
290		}
291		keyNode := &yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: key}
292		valueNode := &yaml.Node{Kind: yaml.MappingNode}
293		parent.Content = append(parent.Content, keyNode, valueNode)
294		return valueNode
295	}
296	
297	func setScalarNode(parent *yaml.Node, key string, value string) {
298		for i := 0; i < len(parent.Content); i += 2 {
299			k := parent.Content[i]
300			if k.Value == key {
301				parent.Content[i+1] = &yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: value}
302				return
303			}
304		}
305		parent.Content = append(parent.Content,
306			&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: key},
307			&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: value},
308		)
309	}
310	
311	func setMappingNode(parent *yaml.Node, key string, values map[string]string) {
312		mapping := &yaml.Node{Kind: yaml.MappingNode}
313		if len(values) > 0 {
314			keys := make([]string, 0, len(values))
315			for k := range values {
316				keys = append(keys, k)
317			}
318			sort.Strings(keys)
319			for _, k := range keys {
320				mapping.Content = append(mapping.Content,
321					&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: k},
322					&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: values[k]},
323				)
324			}
325		}
326		for i := 0; i < len(parent.Content); i += 2 {
327			k := parent.Content[i]
328			if k.Value == key {
329				parent.Content[i+1] = mapping
330				return
331			}
332		}
333		parent.Content = append(parent.Content,
334			&yaml.Node{Kind: yaml.ScalarNode, Tag: "!!str", Value: key},
335			mapping,
336		)
337	}
338	
339	func findMappingValue(node *yaml.Node, key string) *yaml.Node {
340		if node == nil || node.Kind != yaml.MappingNode {
341			return nil
342		}
343		for i := 0; i < len(node.Content); i += 2 {
344			k := node.Content[i]
345			if k.Value == key {
346				return node.Content[i+1]
347			}
348		}
349		return nil
350	}
351	
352	func findMappingKey(node *yaml.Node, key string) *yaml.Node {
353		if node == nil || node.Kind != yaml.MappingNode {
354			return nil
355		}
356		for i := 0; i < len(node.Content); i += 2 {
357			k := node.Content[i]
358			if k.Value == key {
359				return k
360			}
361		}
362		return nil
363	}
364	
365	func mergeIntoDDX(ddxNode *yaml.Node, dunNode *yaml.Node) {
366		if ddxNode == nil || dunNode == nil {
367			return
368		}
369		if ddxNode.Kind != yaml.MappingNode {
370			ddxNode.Kind = yaml.MappingNode
371		}
372		if dunNode.Kind != yaml.MappingNode {
373			return
374		}
375	
376		existing := map[string]struct{}{}
377		for i := 0; i < len(ddxNode.Content); i += 2 {
378			existing[ddxNode.Content[i].Value] = struct{}{}
379		}
380	
381		merged := false
382		for i := 0; i < len(dunNode.Content); i += 2 {
383			keyNode := dunNode.Content[i]
384			valNode := dunNode.Content[i+1]
385			if keyNode == nil || valNode == nil {
386				continue
387			}
388			if _, ok := existing[keyNode.Value]; ok {
389				continue
390			}
391			clonedValue := cloneNode(valNode)
392			ddxNode.Content = append(ddxNode.Content, &yaml.Node{
393				Kind:  keyNode.Kind,
394				Tag:   keyNode.Tag,
395				Value: keyNode.Value,
396			}, clonedValue)
397			existing[keyNode.Value] = struct{}{}
398			merged = true
399		}
400		if merged {
401			sortMappingNodes(ddxNode)
402		}
403	}
404	
405	func removeMappingKey(node *yaml.Node, key string) {
406		if node == nil || node.Kind != yaml.MappingNode {
407			return
408		}
409		for i := 0; i < len(node.Content); i += 2 {
410			k := node.Content[i]
411			if k.Value == key {
412				node.Content = append(node.Content[:i], node.Content[i+2:]...)
413				return
414			}
415		}
416	}
